customScripts.auth_wire:
(function(){
  function hardNav(ev){
    var href = this.getAttribute('href');
    if (href && href.charAt(0)==='/'){ ev.preventDefault(); ev.stopImmediatePropagation(); window.location.assign(href); }
  }
  function wire(){
    var P = (window.__MF_PLATFORM__ || {}); var auth = P.auth || {};
    var root = (window.__mfCurrentScriptRoot) || document.querySelector('.mfp-member-login') || document;
    var links = root.querySelectorAll('[data-mf-auth]');
    for (var i=0;i<links.length;i++){ var el = links[i]; var k = el.getAttribute('data-mf-auth'); if (auth[k]) el.setAttribute('href', auth[k]); el.setAttribute('data-enhance-nav','false'); if (!el.__mfAuthNav){ el.__mfAuthNav = true; el.addEventListener('click', hardNav, true); } }
    if (auth.isAuthenticated){ var si = root.querySelector('[data-mf-signedin]'); var so = root.querySelector('[data-mf-social]'); if (si) si.hidden = false; if (so) so.style.display='none'; }
  }
  try { wire(); } catch(e){}
  setTimeout(wire, 250); setTimeout(wire, 800);
})();

settings.customCss:
/* Member Login - MegaForm auth template. Scope .mfp.mfp-member-login. ASCII-only comments. */
.mfp.mfp-member-login, .mfp.mfp-member-login * { box-sizing: border-box; }
.mfp.mfp-member-login {
  --mfl-primary: var(--mf-preset-primary, #4f46e5);
  --mfl-text: var(--mf-preset-text, #1e293b);
  --mfl-surface: var(--mf-preset-surface, #ffffff);
  --mfl-border: var(--mf-preset-border, #e2e8f0);
  font-family: inherit;
  display: flex; align-items: center; justify-content: center;
  width: 100%; max-width: 440px; margin: 0 auto; padding: 8px;
  color: var(--mfl-text);
}
.mfp.mfp-member-login .mfl-card {
  width: 100%;
  background: var(--mfl-surface);
  border: 1px solid var(--mfl-border);
  border-radius: 16px;
  box-shadow: 0 20px 50px -24px rgba(30,41,59,.35);
  padding: 34px 32px 30px;
}
.mfp.mfp-member-login .mfl-brand { text-align: center; margin-bottom: 24px; }
.mfp.mfp-member-login .mfl-logo {
  width: 52px; height: 52px; margin: 0 auto 14px;
  display: flex; align-items: center; justify-content: center;
  border-radius: 14px; font-size: 22px; color: #fff;
  background: var(--mfl-primary);
}
.mfp.mfp-member-login .mfl-title { margin: 0; font-size: 24px; line-height: 1.2; font-weight: 800; letter-spacing: -0.01em; }
.mfp.mfp-member-login .mfl-sub { margin: 6px 0 0; font-size: 14px; color: color-mix(in srgb, var(--mfl-text) 62%, transparent); }
.mfp.mfp-member-login .mfl-social { display: grid; gap: 10px; }
.mfp.mfp-member-login .mfl-btn {
  display: flex; align-items: center; justify-content: center; gap: 10px;
  width: 100%; min-height: 46px; padding: 11px 16px;
  border-radius: 10px; border: 1px solid var(--mfl-border);
  font: inherit; font-size: 15px; font-weight: 600; text-decoration: none;
  cursor: pointer; transition: transform .06s ease, box-shadow .15s ease, background .15s ease, border-color .15s ease;
}
.mfp.mfp-member-login .mfl-btn:active { transform: translateY(1px); }
.mfp.mfp-member-login .mfl-btn .mfl-ic { display: inline-flex; align-items: center; }
.mfp.mfp-member-login .mfl-btn-facebook { background: #1877F2; color: #fff; border-color: #1877F2; }
.mfp.mfp-member-login .mfl-btn-facebook:hover { background: #0f6ae0; }
.mfp.mfp-member-login .mfl-btn-facebook .mfl-ic { color: #fff; }
.mfp.mfp-member-login .mfl-btn-github { background: #1f2328; color: #fff; border-color: #1f2328; }
.mfp.mfp-member-login .mfl-btn-github:hover { background: #30363d; }
.mfp.mfp-member-login .mfl-btn-github .mfl-ic { color: #fff; }
.mfp.mfp-member-login .mfl-divider { display: flex; align-items: center; gap: 12px; margin: 18px 0; color: color-mix(in srgb, var(--mfl-text) 45%, transparent); font-size: 12px; text-transform: uppercase; letter-spacing: .08em; }
.mfp.mfp-member-login .mfl-divider::before, .mfp.mfp-member-login .mfl-divider::after { content: ""; flex: 1 1 auto; height: 1px; background: var(--mfl-border); }
.mfp.mfp-member-login .mfl-btn-ghost { background: transparent; color: var(--mfl-text); }
.mfp.mfp-member-login .mfl-btn-ghost:hover { border-color: var(--mfl-primary); color: var(--mfl-primary); }
.mfp.mfp-member-login .mfl-btn-primary { background: var(--mfl-primary); color: #fff; border-color: var(--mfl-primary); }
.mfp.mfp-member-login .mfl-foot { margin: 18px 0 0; text-align: center; font-size: 14px; color: color-mix(in srgb, var(--mfl-text) 62%, transparent); }
.mfp.mfp-member-login .mfl-link { color: var(--mfl-primary); font-weight: 600; text-decoration: none; }
.mfp.mfp-member-login .mfl-link:hover { text-decoration: underline; }
.mfp.mfp-member-login .mfl-signedin { text-align: center; display: grid; gap: 12px; margin-bottom: 20px; padding: 14px; border: 1px solid var(--mfl-border); border-radius: 12px; background: color-mix(in srgb, var(--mfl-primary) 6%, transparent); }
.mfp.mfp-member-login .mfl-signedin-msg { margin: 0; font-size: 14px; font-weight: 600; }
@media (max-width: 480px) { .mfp.mfp-member-login .mfl-card { padding: 26px 20px; } }
/* MF-FIX member-login-polish 20260706 - hide the spurious default form submit (a login
   template has no data submit) + lock oauth button text colours over the host link colour. */
.mf-form-wrapper:has(.mfp.mfp-member-login) .mf-form-actions,.mfp.mfp-member-login .mf-form-actions{display:none!important}
.mfp.mfp-member-login .mfl-btn-facebook,.mfp.mfp-member-login .mfl-btn-facebook span{color:#ffffff!important}
.mfp.mfp-member-login .mfl-btn-github,.mfp.mfp-member-login .mfl-btn-github span{color:#ffffff!important}
